update notice_tbl set 
	notice_title = #{noticeTitle},
	notice_content = #{noticeContent},
	notice_public = #{noticePublic},
	notice_fixed = #{noticeFixed}
where notice_no = #{noticeNo}

update faq_tbl set 
	faq_title = #{faqTitle},
	faq_content = #{faqContent},
	faq_category = #{faqCategory}
where faq_no = #{faqNo}
